import { useParams } from "react-router-dom";
import { useState, useEffect } from "react";

/* ---------- CHART FIX (SAFE IMPORT) ---------- */
import {
  Chart as ChartJS,
  LineElement,
  CategoryScale,
  LinearScale,
  PointElement,
  Tooltip,
  Legend
} from "chart.js";

import { Line } from "react-chartjs-2";

/* ---------- REGISTER COMPONENTS ---------- */
ChartJS.register(
  LineElement,
  CategoryScale,
  LinearScale,
  PointElement,
  Tooltip,
  Legend
);

/* ---------- SEVERITY MAP ---------- */
const severityMap = {
  P0: 4,
  P1: 3,
  P2: 2,
  P3: 1
};

export default function IncidentDetail() {
  const { id } = useParams();

  const [trend, setTrend] = useState([]);
  const [loading, setLoading] = useState(true);
  const [closing, setClosing] = useState(false);

  const [form, setForm] = useState({
    start: "",
    end: "",
    rootCause: "",
    fix: "",
    prevention: ""
  });

  /* ---------- FETCH TREND ---------- */
  useEffect(() => {
    fetch(`http://localhost:8000/incident/${id}/trend`)
      .then((res) => res.json())
      .then((data) => {
        setTrend(Array.isArray(data) ? data : []);
        setLoading(false);
      })
      .catch(() => {
        alert("Failed to load trend");
        setLoading(false);
      });
  }, [id]);

  /* ---------- FORM HANDLER ---------- */
  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  /* ---------- CLOSE INCIDENT ---------- */
  const handleSubmit = async (e) => {
    e.preventDefault();
    setClosing(true);

    try {
      const res = await fetch(`http://localhost:8000/close/${id}`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json"
        },
        body: JSON.stringify(form)
      });

      const data = await res.json();

      if (data.error) {
        alert(data.error);
      } else {
        alert("Incident Closed ✅");
      }
    } catch {
      alert("Failed to close incident");
    }

    setClosing(false);
  };

  /* ---------- CHART DATA ---------- */
  const chartData = {
    labels: trend.map((t) =>
      new Date(t.time).toLocaleTimeString()
    ),
    datasets: [
      {
        label: "Severity Trend",
        data: trend.map((t) => severityMap[t.severity] || 0),
        borderColor: "#2f6fed",
        borderWidth: 2,
        tension: 0.3,
        fill: false
      }
    ]
  };

  const chartOptions = {
    responsive: true,
    plugins: {
      legend: {
        display: true
      }
    },
    scales: {
      y: {
        ticks: {
          callback: function (value) {
            return ["", "P3", "P2", "P1", "P0"][value];
          }
        },
        min: 1,
        max: 4
      }
    }
  };

  return (
    <div style={page}>
      <h2>Incident #{id}</h2>

      {/* ---------- TREND GRAPH ---------- */}
      <div style={card}>
        <h3>📊 Severity Trend</h3>

        {loading ? (
          <p>Loading chart...</p>
        ) : trend.length > 0 ? (
          <Line data={chartData} options={chartOptions} />
        ) : (
          <p>No trend data available</p>
        )}
      </div>

      {/* ---------- RCA FORM ---------- */}
      <div style={card}>
        <h3>🛠 Close Incident (RCA)</h3>

        <form onSubmit={handleSubmit} style={formStyle}>
          <input
            type="datetime-local"
            name="start"
            onChange={handleChange}
            required
          />

          <input
            type="datetime-local"
            name="end"
            onChange={handleChange}
            required
          />

          <input
            name="rootCause"
            placeholder="Root Cause"
            onChange={handleChange}
            required
          />

          <input
            name="fix"
            placeholder="Fix"
            onChange={handleChange}
          />

          <input
            name="prevention"
            placeholder="Prevention"
            onChange={handleChange}
          />

          <button type="submit" disabled={closing}>
            {closing ? "Closing..." : "Close Incident"}
          </button>
        </form>
      </div>
    </div>
  );
}

/* ---------- STYLES ---------- */
const page = {
  padding: "20px",
  background: "#f4f6f8",
  minHeight: "100vh",
  fontFamily: "Segoe UI"
};

const card = {
  background: "#fff",
  padding: "20px",
  borderRadius: "12px",
  marginTop: "20px",
  boxShadow: "0 2px 8px rgba(0,0,0,0.08)"
};

const formStyle = {
  display: "flex",
  flexDirection: "column",
  gap: "10px"
};
